), upserted_workshop as (
  insert into public.workshops
    (name, slug, status, country_code, province, municipality, postal_code, address_line, location, phone, email, website, opening_hours, source_confidence, data_quality_status, raw_attributes)
  values
    (
      'Dima Vulco',
      'dima-vulco-8c0b4436',
      'published',
      'ES',
      null,
      null,
      '11011',
      'Calle Gibraltar',
      extensions.st_setsrid(extensions.st_makepoint(-6.2691759, 36.4972809), 4326)::extensions.geography,
      '+34 658 98 43 53',
      'dimacadiz@vulco.es',
      'https://dimacadiz.vulco.es/',
      '{"osm": "Mo-Fr 09:00-14:00,16:00-20:00; Sa 09:30-14:00"}'::jsonb,
      0.73,
      'imported',
      '{"features": [], "osm_id": 5537430622, "osm_type": "node", "source": "osm", "tags": {"addr:postcode": "11011", "addr:street": "Calle Gibraltar", "email": "dimacadiz@vulco.es", "name": "Dima Vulco", "nohousenumber": "yes", "opening_hours": "Mo-Fr 09:00-14:00,16:00-20:00; Sa 09:30-14:00", "phone": "+34 658 98 43 53", "shop": "car_repair", "website": "https://dimacadiz.vulco.es/"}}'::jsonb
    )
  on conflict (slug) do update
  set
    name = excluded.name,
    province = excluded.province,
    municipality = excluded.municipality,
    postal_code = excluded.postal_code,
    address_line = excluded.address_line,
    location = excluded.location,
    phone = coalesce(excluded.phone, public.workshops.phone),
    email = coalesce(excluded.email, public.workshops.email),
    website = coalesce(excluded.website, public.workshops.website),
    opening_hours = excluded.opening_hours,
    source_confidence = excluded.source_confidence,
    data_quality_status = 'imported',
    raw_attributes = excluded.raw_attributes,
    updated_at = now()
  returning id
)
insert into public.workshop_external_ids (workshop_id, source_id, external_id, raw_url, last_seen_at)
select
  upserted_workshop.id,
  source.id,
  'osm:node:5537430622',
  'https://www.openstreetmap.org/node/5537430622',
  now()
from upserted_workshop, source
on conflict (source_id, external_id) do update
set workshop_id = excluded.workshop_id,
    raw_url = excluded.raw_url,
    last_seen_at = now();
insert into public.workshop_services (workshop_id, service_category_id)
select w.id, sc.id
from public.workshops w
join public.service_categories sc on sc.code = 'maintenance'
where w.slug = 'dima-vulco-8c0b4436'
on conflict (workshop_id, service_category_id) do nothing;
insert into public.workshop_services (workshop_id, service_category_id)
select w.id, sc.id
from public.workshops w
join public.service_categories sc on sc.code = 'mechanical_repair'
where w.slug = 'dima-vulco-8c0b4436'
on conflict (workshop_id, service_category_id) do nothing;

